export function parseArgs(argv) {
  const result = { _: [] }
  let i = 0
  while (i < argv.length) {
    const arg = argv[i]
    if (arg.startsWith('--')) {
      const key = arg.slice(2)
      if (key.includes('=')) {
        result[key] = key.split('=')[1]
        i++
      } else if (i + 1 < argv.length && !argv[i + 1].startsWith('--')) {
        result[key] = argv[i + 1]
        i += 2
      } else {
        result[key] = true
        i++
      }
    } else {
      result._.push(arg)
      i++
    }
  }
  return result
}

